package main

import (
	"fmt"
	"strconv"
	"strings"
)

func isPalindrome(text string) bool {
	cleaned := strings.ToLower(strings.ReplaceAll(text, " ", ""))

	runes := []rune(cleaned)
	left, right := 0, len(runes)-1

	for left < right {
		if runes[left] != runes[right] {
			return false
		}
		left++
		right--
	}
	return true
}

func isNumberPalindrome(number int) bool {
	text := strconv.Itoa(number)
	return isPalindrome(text)
}

func main() {
	words := []string{"kayak", "araba", "anna", "elma", "a man a plan a canal panama"}

	fmt.Println("Kelime testleri:")
	for _, word := range words {
		fmt.Printf("'%s' palindrome mu: %v\n", word, isPalindrome(word))
	}

	fmt.Println("\nSayi testleri:")
	numbers := []int{12321, 12345, 1001, 5}
	for _, num := range numbers {
		fmt.Println(num, "palindrome mu:", isNumberPalindrome(num))
	}
}
